if (! function_exists('text_sentiment_analysis')) {
    function text_sentiment_analysis($text)
    {
        $positiveWords = [
            'happy', 'love', 'wonderful', 'great', 'amazing', 'beautiful', 'excellent',
            'fantastic', 'good', 'nice', 'joy', 'peace', 'hope', 'bright', 'brilliant',
            'awesome', 'incredible', 'perfect', 'superb', 'delightful', 'glad', 'cheerful',
            'optimistic', 'positive', 'success', 'win', 'triumph', 'celebrate', 'paradise',
            'heaven', 'bliss', 'euphoria', 'ecstasy', 'radiant', 'splendid', 'magnificent',
            'marvelous', 'wondrous', 'fabulous', 'terrific', 'smile', 'laugh', 'fun',
            'enjoy', 'thrilled', 'elated', 'grateful', 'thankful', 'blessed', 'prosperous',
            'generous', 'kind', 'compassionate', 'loving', 'caring', 'tender', 'warm',
            'friendly', 'graceful', 'elegant', 'vibrant', 'energetic', 'vibrant', 'sunshine',
            'celebration', 'victory', 'achievement', 'masterpiece', 'gem', 'treasure',
            'courage', 'brave', 'hero', 'champion', 'genius', 'wisdom', 'inspire',
        ];

        $negativeWords = [
            'sad', 'angry', 'hate', 'terrible', 'awful', 'horrible', 'bad', 'ugly',
            'evil', 'pain', 'suffering', 'misery', 'cry', 'tears', 'grief', 'sorrow',
            'despair', 'hopeless', 'gloom', 'dark', 'dread', 'fear', 'terror', 'horror',
            'disaster', 'catastrophe', 'tragedy', 'calamity', 'ruin', 'destroy', 'devastate',
            'cruel', 'wicked', 'vile', 'hideous', 'disgusting', 'revolting', 'repulsive',
            'toxic', 'poison', 'deadly', 'fatal', 'mourn', 'funeral', 'grave', 'death',
            'agony', 'torture', 'torment', 'anguish', 'depress', 'miserable', 'wretched',
            'lonely', 'isolated', 'abandoned', 'betrayed', 'broken', 'shatter', 'collapse',
            'fail', 'failure', 'loss', 'defeat', 'humiliate', 'ashamed', 'guilty',
            'jealous', 'envy', 'greed', 'selfish', 'corrupt', 'decay', 'rotten',
            'danger', 'peril', 'hazard', 'risk', 'threat', 'attack', 'war', 'conflict',
            'violence', 'brutal', 'savage', 'furious', 'rage', 'wrath', 'venom',
        ];

        $positiveWords = array_unique($positiveWords);
        $negativeWords = array_unique($negativeWords);

        $words = preg_split('/\s+/', strtolower(trim($text)));
        $words = array_filter($words, function($w) { return preg_match('/[a-z]/', $w); });

        $positiveCount = 0;
        $negativeCount = 0;
        $foundPositive = [];
        $foundNegative = [];

        foreach ($words as $word) {
            $clean = preg_replace('/[^a-z]/', '', $word);
            if (in_array($clean, $positiveWords)) {
                $positiveCount++;
                $foundPositive[] = $clean;
            } elseif (in_array($clean, $negativeWords)) {
                $negativeCount++;
                $foundNegative[] = $clean;
            }
        }

        $total = count($words);
        $neutralCount = $total - $positiveCount - $negativeCount;

        $score = 0;
        if ($positiveCount > 0 || $negativeCount > 0) {
            $score = ($positiveCount - $negativeCount) / max(1, $positiveCount + $negativeCount);
        }

        $sentiment = 'neutral';
        if ($score > 0.3) $sentiment = 'positive';
        elseif ($score > 0.1) $sentiment = 'mildly_positive';
        elseif ($score < -0.3) $sentiment = 'negative';
        elseif ($score < -0.1) $sentiment = 'mildly_negative';

        return json_encode([
            'text' => $text,
            'word_count' => $total,
            'score' => round($score, 4),
            'sentiment' => $sentiment,
            'positive_count' => $positiveCount,
            'negative_count' => $negativeCount,
            'neutral_count' => $neutralCount,
            'positive_words' => array_values(array_unique($foundPositive)),
            'negative_words' => array_values(array_unique($foundNegative)),
        ]);
    }
